#include "kernel_operator.h"
#include "kernel_math.h"
#include "matmul_api.h"

using namespace AscendC;

constexpr int32_t BUFFER_NUM = 2;

class KernelVanillaRnnHiddenCustom {
public:
    __aicore__ inline KernelVanillaRnnHiddenCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR h0, GM_ADDR w_i2h, GM_ADDR b_i2h,
                                GM_ADDR w_h2o, GM_ADDR b_h2o, GM_ADDR y,
                                uint32_t T, uint32_t B, uint32_t I, uint32_t H, uint32_t O)
    {
        T_ = T; B_ = B; I_ = I; H_ = H; O_ = O; K_ = I + H;

        xGm_.SetGlobalBuffer((__gm__ float*)x, T_ * B_ * I_);
        h0Gm_.SetGlobalBuffer((__gm__ float*)h0, B_ * H_);
        // w_i2h (H, K) split into w_x (H, I) and w_h (H, H)
        w_xGm_.SetGlobalBuffer((__gm__ float*)w_i2h, H_ * I_);
        w_hGm_.SetGlobalBuffer((__gm__ float*)w_i2h + H_ * I_, H_ * H_);
        b_i2hGm_.SetGlobalBuffer((__gm__ float*)b_i2h, H_);
        w_h2oGm_.SetGlobalBuffer((__gm__ float*)w_h2o, O_ * H_);
        b_h2oGm_.SetGlobalBuffer((__gm__ float*)b_h2o, O_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, T_ * B_ * O_);

        // Initialize local buffers
        pipe_.InitBuffer(bufX_, 1, I_ * sizeof(float));
        pipe_.InitBuffer(bufH_, 1, H_ * sizeof(float));
        pipe_.InitBuffer(bufPreA_, 1, H_ * sizeof(float));
        pipe_.InitBuffer(bufPreB_, 1, H_ * sizeof(float));
        pipe_.InitBuffer(bufPre_, 1, H_ * sizeof(float));
        pipe_.InitBuffer(bufYRaw_, 1, O_ * sizeof(float));
        pipe_.InitBuffer(bufY_, 1, O_ * sizeof(float));
        pipe_.InitBuffer(bufBiasI2H_, 1, H_ * sizeof(float));
        pipe_.InitBuffer(bufBiasH2O_, 1, O_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (T_ == 0 || B_ == 0) return;

        const uint32_t blockNum = GetBlockNum();
        const uint32_t blockIdx = GetBlockIdx();

        // Load biases into local once
        LocalTensor<float> biasI2H = bufBiasI2H_.Get<float>();
        LocalTensor<float> biasH2O = bufBiasH2O_.Get<float>();
        DataCopy(biasI2H, b_i2hGm_, H_);
        DataCopy(biasH2O, b_h2oGm_, O_);

        // Grid-stride over batches
        for (uint32_t b = blockIdx; b < B_; b += blockNum) {
            // Load initial hidden state for this batch
            LocalTensor<float> hLocal = bufH_.Get<float>();
            DataCopy(hLocal, h0Gm_[b * H_], H_);

            for (uint32_t t = 0; t < T_; ++t) {
                // Load x[t, b, :]
                LocalTensor<float> xLocal = bufX_.Get<float>();
                DataCopy(xLocal, xGm_[(t * B_ + b) * I_], I_);

                // preA = x * w_x^T  (x:1xI, w_x:HxI => 1xH)
                LocalTensor<float> preA = bufPreA_.Get<float>();
                MatMul<false, true>(preA, xLocal, w_xGm_, 1, H_, I_, I_, H_, H_);

                // preB = h * w_h^T  (h:1xH, w_h:HxH => 1xH)
                LocalTensor<float> preB = bufPreB_.Get<float>();
                MatMul<false, true>(preB, hLocal, w_hGm_, 1, H_, H_, H_, H_, H_);

                // pre = preA + preB + biasI2H
                LocalTensor<float> pre = bufPre_.Get<float>();
                Add(pre, preA, preB, H_);
                Add(pre, pre, biasI2H, H_);
                Tanh(pre, pre, H_);
                // update hLocal
                DataCopy(hLocal, pre, H_);

                // y = h * w_h2o^T + biasH2O  (h:1xH, w_h2o:OxH => 1xO)
                LocalTensor<float> yRaw = bufYRaw_.Get<float>();
                MatMul<false, true>(yRaw, hLocal, w_h2oGm_, 1, O_, H_, H_, H_, O_);
                LocalTensor<float> yLocal = bufY_.Get<float>();
                Add(yLocal, yRaw, biasH2O, O_);
                DataCopy(yGm_[(t * B_ + b) * O_], yLocal, O_);
            }
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufX_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufH_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufPreA_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufPreB_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufPre_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufYRaw_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufY_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufBiasI2H_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufBiasH2O_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> h0Gm_;
    AscendC::GlobalTensor<float> w_xGm_;
    AscendC::GlobalTensor<float> w_hGm_;
    AscendC::GlobalTensor<float> b_i2hGm_;
    AscendC::GlobalTensor<float> w_h2oGm_;
    AscendC::GlobalTensor<float> b_h2oGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t T_{0}, B_{0}, I_{0}, H_{0}, O_{0}, K_{0};
};

extern "C" __global__ __aicore__ void vanilla_rnn_hidden_custom(
    GM_ADDR x, GM_ADDR h0, GM_ADDR w_i2h, GM_ADDR b_i2h,
    GM_ADDR w_h2o, GM_ADDR b_h2o, GM_ADDR y,
    GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelVanillaRnnHiddenCustom op;
    op.Init(x, h0, w_i2h, b_i2h, w_h2o, b_h2o, y,
            tiling_data.T, tiling_data.B, tiling_data.I, tiling_data.H, tiling_data.O);
    op.Process();
}
